func solve(sx int64, sy int64, tx int64, ty int64) int64 {
	// If start is already the target
	if sx == tx && sy == ty {
		return 0
	}

	// If target is not reachable, return -1
	if (tx < sx || ty < sy) || ((sx+sy)%2 != (tx+ty)%2) {
		return -1
	}

	steps := 0
	for sx < tx || sy < ty {
		m := max(sx, sy)
		if sx < tx {
			sx += m
			steps++
		} else {
			sy += m
			steps++
		}
	}
	return int64(steps)
}

func max(a, b int64) int64 {
	if a > b {
		return a
	}
	return b
}
